12	const BASE_PREMIUMS: Record<string, number> = {
13	  sword: 100,
14	  amulet: 60,
15	  staff: 80,
16	  potion: 40,
17	  rune: 25,
18	};
19	
20	const BLOCK_PRICE_FOR_3_ALIKE = 60;
21	const CURSED_SURCHARGE_MULTIPLIER = 1.5;
22	const ENCHANTMENT_SURCHARGE_MULTIPLIER = 0.3;
23	const FIRST_INSURANCE_SURCHARGE_MULTIPLIER = 1.1;
24	const FOLLOW_UP_CONTRACT_DISCOUNT_MULTIPLIER = 0.85;
25	const LOYALTY_DISCOUNT_MULTIPLIER = 0.8;
26	const LOYALTY_DISCOUNT_MIN_YEARS = 2;
27	const HIGH_ENCHANTMENT_THRESHOLD = 5;
28	const FOLLOW_UP_CONTRACT_MIN_COUNT = 1;
29	
30	const roundToCents = (amount: number): number => Math.round(amount * 100) / 100;
31	
32	const PROCESSING_FEE = 5;
33	
34	const calculateItemCosts = (items: Item[]): number => {
35	  const nonCursedCountsByType: Record<string, number> = {};
36	  let cursedCost = 0;
37	  let enchantmentSurcharge = 0;
38	
39	  for (const item of items) {
40	    const itemBasePremium = BASE_PREMIUMS[item.type];
41	    if (item.cursed) {
42	      cursedCost += itemBasePremium * CURSED_SURCHARGE_MULTIPLIER;
43	    } else {
44	      nonCursedCountsByType[item.type] = (nonCursedCountsByType[item.type] ?? 0) + 1;
45	      if (item.enchantment !== undefined && item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
46	        enchantmentSurcharge += itemBasePremium * ENCHANTMENT_SURCHARGE_MULTIPLIER;
47	      }
48	    }
49	  }
50	
51	  let nonCursedCost = 0;
52	  for (const [type, count] of Object.entries(nonCursedCountsByType)) {
53	    if (count === 3) {
54	      nonCursedCost += BLOCK_PRICE_FOR_3_ALIKE;
55	    } else {
56	      nonCursedCost += count * BASE_PREMIUMS[type];
57	    }
58	  }
59	
60	  return cursedCost + nonCursedCost + enchantmentSurcharge;
61	};
62	
63	export function generateQuote(items: Item[], customer: Customer): { basePremium: number; premium: number } {
64	  let basePremium = calculateItemCosts(items);
65	
66	  basePremium *= FIRST_INSURANCE_SURCHARGE_MULTIPLIER;
67	
68	  if (customer.contractCount >= FOLLOW_UP_CONTRACT_MIN_COUNT) {
69	    basePremium *= FOLLOW_UP_CONTRACT_DISCOUNT_MULTIPLIER;
70	  }
71	
72	  if (customer.yearsWithMHPCO >= LOYALTY_DISCOUNT_MIN_YEARS) {
73	    basePremium *= LOYALTY_DISCOUNT_MULTIPLIER;
74	  }
75	
76	  const roundedBasePremium = roundToCents(basePremium);
77	  return { basePremium: roundedBasePremium, premium: Math.ceil(roundedBasePremium + PROCESSING_FEE) };
78	}
