80	const DEDUCTIBLE = 100;
81	
82	interface Policy {
83	  basePremium: number;
84	  premium: number;
85	}
86	
87	interface Damage {
88	  itemType: string;
89	  amount: number;
90	}
91	
92	interface Incident {
93	  cause: string;
94	  damages: Damage[];
95	}
96	
97	export function processClaim(policy: Policy, incident: Incident): { payout: number; remainingCap: number } {
98	  const damage = incident.damages[0].amount;
99	  const payout = damage - DEDUCTIBLE;
100	  return { payout, remainingCap: 0 };
101	}
